import React, { useState, useMemo } from 'react';
import competitions from '../data/competitions';
import HackathonCard from '../components/HackathonCard';
import styles from './Competitions.module.css';

export default function Competitions() {
  const categories = useMemo(() => {
    const set = new Set(competitions.map((c) => c.category));
    return Array.from(set);
  }, []);

  const [selected, setSelected] = useState(new Set());

  function toggleCategory(cat) {
    const next = new Set(selected);
    if (next.has(cat)) next.delete(cat);
    else next.add(cat);
    setSelected(next);
  }

  const filtered = useMemo(() => {
    if (selected.size === 0) return competitions;
    return competitions.filter((c) => selected.has(c.category));
  }, [selected]);

  return (
    <section className={styles.page}>
      <h2>Змагання</h2>
      <div className={styles.filters}>
        <strong>Фільтрувати за категоріями:</strong>
        <div className={styles.tags}>
          {categories.map((cat) => (
            <label key={cat} className={styles.tag}>
              <input
                type="checkbox"
                checked={selected.has(cat)}
                onChange={() => toggleCategory(cat)}
              />
              {cat}
            </label>
          ))}
        </div>
      </div>

      <div className={styles.list}>
        {filtered.map((c) => (
          <HackathonCard key={c.id} hackathon={c} />
        ))}
        {filtered.length === 0 && <p>Нічого не знайдено для обраних фільтрів.</p>}
      </div>
    </section>
  );
}
